import numpy as np
from collections import Counter

class Node:
    def __init__(self, feature=None, threshold=None, left=None, right=None, *, value=None):
        self.feature = feature
        self.threshold = threshold
        self.left = left
        self.right = right
        self.value = value  # set only for leaf nodes

    def is_leaf(self):
        return self.value is not None


class DecisionTreeClassifier:
    def __init__(self, max_depth=10, min_samples_split=2, criterion="gini"):
        self.max_depth = max_depth
        self.min_samples_split = min_samples_split
        self.criterion = criterion
        self.root = None

    # ── Impurity ───────────────────────────────────────────────────────────────
    def _gini(self, y):
        n = len(y)
        counts = Counter(y)
        return 1.0 - sum((c / n) ** 2 for c in counts.values())

    def _entropy(self, y):
        n = len(y)
        counts = Counter(y)
        return -sum((c / n) * np.log2(c / n + 1e-12) for c in counts.values())

    def _impurity(self, y):
        return self._gini(y) if self.criterion == "gini" else self._entropy(y)

    # ── Best split ─────────────────────────────────────────────────────────────
    def _best_split(self, X, y):
        n_samples, n_features = X.shape
        best_gain, best_feat, best_thresh = -1, None, None

        parent_imp = self._impurity(y)

        for feat in range(n_features):
            thresholds = np.unique(X[:, feat])
            for t in thresholds:
                left_mask = X[:, feat] <= t
                right_mask = ~left_mask
                if left_mask.sum() == 0 or right_mask.sum() == 0:
                    continue

                n_l, n_r = left_mask.sum(), right_mask.sum()
                gain = parent_imp - (n_l / n_samples) * self._impurity(y[left_mask])                                   - (n_r / n_samples) * self._impurity(y[right_mask])
                if gain > best_gain:
                    best_gain, best_feat, best_thresh = gain, feat, t

        return best_feat, best_thresh

    # ── Recursive build ────────────────────────────────────────────────────────
    def _build(self, X, y, depth):
        # Stopping conditions
        if (depth >= self.max_depth
                or len(y) < self.min_samples_split
                or len(set(y)) == 1):
            return Node(value=Counter(y).most_common(1)[0][0])

        feat, thresh = self._best_split(X, y)
        if feat is None:
            return Node(value=Counter(y).most_common(1)[0][0])

        mask = X[:, feat] <= thresh
        left  = self._build(X[mask],  y[mask],  depth + 1)
        right = self._build(X[~mask], y[~mask], depth + 1)
        return Node(feature=feat, threshold=thresh, left=left, right=right)

    def fit(self, X, y):
        self.root = self._build(np.array(X), np.array(y), depth=0)
        return self

    # ── Inference ─────────────────────────────────────────────────────────────
    def _traverse(self, node, x):
        if node.is_leaf():
            return node.value
        if x[node.feature] <= node.threshold:
            return self._traverse(node.left, x)
        return self._traverse(node.right, x)

    def predict(self, X):
        return np.array([self._traverse(self.root, x) for x in X])


# Quick test
from sklearn.datasets import load_iris
from sklearn.model_selection import train_test_split
from sklearn.metrics import accuracy_score

X, y = load_iris(return_X_y=True)
X_train, X_test, y_train, y_test = train_test_split(X, y, random_state=42)

tree = DecisionTreeClassifier(max_depth=5)
tree.fit(X_train, y_train)
preds = tree.predict(X_test)
print(f"Accuracy: {accuracy_score(y_test, preds):.3f}")   # ≈ 0.947
